%%%%%%%%%% Function vrnSF2.m %%%%%%%%%%% Function Varian Start and Finish, ver.2% Kei Nakamura% Created on Wednesday, May 6th 2006.% Modified on Monday, May 15th 2006.%% function [strt fns stpN] = vrnSF2(x stpV)% returns the start value and step number for plotting.function [strt fns stpN] = vrnSF2(x,stpV)  %function headerminX = min(x);maxX = max(x);pp = 1; strt = 0;while pp~=0;    cv = minX+(pp-1.5)*stpV;   % current value    if minX>cv;        strt = cv;    end    if maxX<cv;        fns = cv;        pp = -1;    end    pp = pp + 1;endstpN = (fns-strt)/stpV +1;
